const body = $input.first().json.body || $input.first().json;

const owner_user_id  = body.owner_user_id || null;
const invitee_email  = (body.invitee_email || '').toLowerCase().trim();
const seat_role      = (body.seat_role || 'viewer').toLowerCase().trim();

if (!owner_user_id)  throw new Error('Missing required field: owner_user_id');
if (!invitee_email)  throw new Error('Missing required field: invitee_email');

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(invitee_email)) throw new Error(`Invalid invitee_email: ${invitee_email}`);

const validRoles = ['viewer', 'editor', 'admin'];
const resolvedRole = validRoles.includes(seat_role) ? seat_role : 'viewer';

// Generate a unique invite token
const token_raw = `${owner_user_id}-${invitee_email}-${Date.now()}`;
const invite_token = Buffer.from(token_raw).toString('base64').replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_').substring(0, 32);

const roleLabels = {
  viewer: 'Viewer (read-only access)',
  editor: 'Editor (can create and edit)',
  admin:  'Admin (full team management)'
};

return [{
  json: {
    owner_user_id,
    invitee_email,
    seat_role: resolvedRole,
    role_label: roleLabels[resolvedRole],
    invite_token,
    now: new Date().toISOString()
  }
}];

const fetchResult = $input.first().json;
const origin = $('Parse & Validate').first().json;

const record = Array.isArray(fetchResult) ? fetchResult[0] : fetchResult;

if (!record || !record.user_id) {
  throw new Error(`Owner not found in users table: ${origin.owner_user_id}`);
}

const plan_tier   = (record.plan_tier || '').toLowerCase();
const plan_status = (record.plan_status || '').toLowerCase();
const is_scale    = plan_tier === 'scale';
const is_active   = plan_status === 'active';
const team_name   = record.team_name || 'your team';
const owner_email = record.email || '';

return [{
  json: {
    ...origin,
    owner_email,
    owner_plan_tier: plan_tier,
    owner_plan_status: plan_status,
    team_name,
    is_scale,
    is_active,
    authorized: is_scale && is_active
  }
}];

const d = $input.first().json;
const reason = !d.is_scale
  ? `Plan upgrade required. Owner is on '${d.owner_plan_tier}' — multi-seat access requires Scale ($299/mo).`
  : `Account is ${d.owner_plan_status}. Reactivate billing to invite team members.`;

return [{ json: { ...d, denial_reason: reason } }];

const dupResult = $input.first().json;
const origin = $('Check Scale Authorization').first().json;

const existing = Array.isArray(dupResult) ? dupResult[0] : null;
const is_duplicate = !!existing;
const existing_status = existing?.status || null;

return [{
  json: {
    ...origin,
    is_duplicate,
    existing_status
  }
}];

const insertResult = $input.first().json;
const origin = $('Evaluate Duplicate').first().json;

const record = Array.isArray(insertResult) ? insertResult[0] : insertResult;

if (!record || !record.id) {
  throw new Error('team_members INSERT did not return a record — check Supabase RLS policies');
}

// Build the pre-filled signup link with team context
const base_url = process.env.APP_BASE_URL || 'https://app.nova-ops.space';
const signup_link = `${base_url}/join?token=${origin.invite_token}&team=${encodeURIComponent(origin.owner_user_id)}&role=${origin.seat_role}&email=${encodeURIComponent(origin.invitee_email)}`;

return [{
  json: {
    ...origin,
    seat_id: record.id,
    signup_link
  }
}];

