const emailResult = $input.first().json;
const origin = $('Confirm Insert + Build Invite Link').first().json;

const email_id   = emailResult?.id || null;
const email_sent = !!email_id;

if (!email_sent) {
  console.warn(`Invite email may have failed for ${origin.invitee_email}. Resend response: ${JSON.stringify(emailResult)}`);
}

return [{
  json: {
    ...origin,
    email_sent,
    email_id
  }
}];

